import './App.css';
import { useEffect, useRef, useState } from "react";

export default function App() {
  const outputCanvasRef = useRef(null);
  const workerRef = useRef(null);
  const widthRef = useRef(null);

  const[image, setImage] = useState(null);
  const [width, setWidth] = useState(120);
  const [isColor, setIsColor] = useState(false);
  const[contrast, setContrast] = useState(1);

  useEffect(() => {
    workerRef.current = new Worker(
      new URL("./worker.js", import.meta.url),
      { type: "module" }
    );

    workerRef.current.onmessage = (e) => {
      const bitmap = e.data;
      const canvas = outputCanvasRef.current;
      const ctx = canvas.getContext("2d");

      canvas.width = bitmap.width;
      canvas.height = bitmap.height;

      ctx.clearRect(0, 0, canvas.width, canvas.height);
      ctx.drawImage(bitmap, 0, 0);
    };

    return () => workerRef.current.terminate();
  }, []);

  function handleImageUpload(e) {
    const file = e.target.files[0];
    if (!file) return;

    const img = new Image();
    img.src = URL.createObjectURL(file);

    img.onload = () => setImage(img);
  };

  function saveImage() {
    const canvas = outputCanvasRef.current;
    if (!canvas) return;

    canvas.toBlob((blob) => {
      const link = document.createElement("a");
      link.download = "ascii.png";
      link.href = URL.createObjectURL(blob);
      link.click();
    })
  }
  useEffect(() => {
    if (!image || !workerRef.current) return;

    (async () => {
      const bitmap = await createImageBitmap(image);

      const targetWidth = width;
      const targetHeight = Math.round(width * 0.6);

      workerRef.current.postMessage({
        bitmap,
        width: targetWidth,
        height: targetHeight,
        isColor,
        fontSize: 6,
        contrast
      }, [bitmap]);
    })();
  }, [image, width, isColor, contrast]);


  function slider(value, min, max) {
    const percent = ((value - min) / (max - min)) * 100;

    return {
      background: `linear-gradient(
        to right,
        var(--neutral-100) 0%,
        var(--neutral-100) ${percent}%,
        var(--primary-300) ${percent}%,
        var(--primary-300) 100%
      )
      `,
      transition: "background 0.2s ease"
    };
  }

   return (
    <div className='container'>
      <h1 className='card-logo'>ASCII</h1>        

      <canvas 
        ref={outputCanvasRef} 
        style={{ 
          background: "#000",
          imageRendering: "auto", 
        }}
        className='canvas'
      />
      <div className='toolbar'>
          <input 
            type="file" 
            accept="image/*" 
            onChange={handleImageUpload}
            className='uploader'
          />

          <label>
            Width: {width}
           <div className='slider-wrap'>
            <div className="slider-border"></div>
            <input
              type="range"
              min="40"
              max="300"
              step="10"
              value={width}
              ref={widthRef}
              onChange={(e) => setWidth(+e.target.value)}
              onMouseUp={() => {
                // округляем до ближайшего шага
                const snapped = Math.round(width / 10) * 10;
                const input = widthRef.current;
                if (!input) return;

                input.style.transition = "all 0.2s ease";
                setWidth(snapped);

                setTimeout(() => {
                  if (input) input.style.transition = "";
                }, 200);
              }}
              style={slider(width, 40, 300)}
              className='slider'
            />
           </div>
          </label>
          <label>
            Contrast: {contrast.toFixed(2)}
           <div className='slider-wrap'>
            <div className="slider-border"></div>
            <input
              type="range"
              min="0.5"
              max="2.5"
              step="0.1"
              value={contrast}
              onChange={(e) => setContrast(+e.target.value)}
              style={slider(contrast, 0.5, 2.5)}
              className='slider'
            />
           </div>
          </label>
          <label>
            <input
              type="checkbox"
              checked={isColor}
              onChange={(e) => setIsColor(e.target.checked)}
              className='check-box'
            />
            Color
          </label>
      </div>
      <button onClick={saveImage}>
        Save Image
      </button>
    </div>
  );
}
